import{_ as a,o as l,c as i,a2 as e}from"./chunks/framework.DnrXFDHb.js";const A=JSON.parse('{"title":"AI Agent 在电力调度中的应用——从演示品到省级部署","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"AI/_深化_2026-06-16_电力调度AI与Agent.md","filePath":"AI/_深化_2026-06-16_电力调度AI与Agent.md","lastUpdated":1781602495000}'),o={name:"AI/_深化_2026-06-16_电力调度AI与Agent.md"};function d(r,t,u,h,n,q){return l(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="ai-agent-在电力调度中的应用——从演示品到省级部署" tabindex="-1">AI Agent 在电力调度中的应用——从演示品到省级部署 <a class="header-anchor" href="#ai-agent-在电力调度中的应用——从演示品到省级部署" aria-label="Permalink to &quot;AI Agent 在电力调度中的应用——从演示品到省级部署&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>AI Agent 在电力调度领域已从演示品走向省级规模化部署，并非 PPT 产品。广东电网&quot;明月&quot;AI调度员日均处置 100+ 告警信号、拟写 50+ 指令。广西电网&quot;阿度&quot;断面调控智能体秒级感知。长治 AI 机器人将核心业务耗时缩短 80%+。南网&quot;大瓦特&quot;落地 700+ 实景场景。多家已通过知识图谱+强化学习+微调解决&quot;幻觉&quot;问题。主要仍在电网调度侧，市场化交易侧 AI Agent 仍处早期。</p><h2 id="核心案例" tabindex="-1">核心案例 <a class="header-anchor" href="#核心案例" aria-label="Permalink to &quot;核心案例&quot;">​</a></h2><h3 id="广东电网-明月-ai调度员" tabindex="-1">广东电网&quot;明月&quot;AI调度员 <a class="header-anchor" href="#广东电网-明月-ai调度员" aria-label="Permalink to &quot;广东电网&quot;明月&quot;AI调度员&quot;">​</a></h3><ul><li>国内首个多智能体协作省级电网 AI 调度员</li><li>基于南网&quot;大瓦特-天璇&quot;模型底座</li><li>融合知识图谱 + 强化学习 + 大模型微调技术，规避大模型&quot;幻觉&quot;</li><li>日均能力：编制 10+ 调度报表、拟写 50+ 调度指令、处置 100+ 告警信号</li><li>智能话务通知 200+ 次/日，全时段监护安全与市场合规 1000+ 项</li><li>全链条应急处置时间从小时级缩短至 5 分钟内</li><li>工作模式从&quot;一对一&quot;变成&quot;多对多&quot;</li></ul><h3 id="广西电网-阿度-断面调控智能体" tabindex="-1">广西电网&quot;阿度&quot;断面调控智能体 <a class="header-anchor" href="#广西电网-阿度-断面调控智能体" aria-label="Permalink to &quot;广西电网&quot;阿度&quot;断面调控智能体&quot;">​</a></h3><ul><li>基于&quot;大瓦特-天璇&quot;大模型 + 强化学习（GRPO）算法</li><li>秒级感知电网断面状态，智能预测与自主调控</li><li>2024 年底上线，显著提升正常态与极端故障场景控制及时性</li><li>大小模型融合方案（大模型调度、小模型执行分析）</li><li>解决调度监控中海量告警信号辨识难题</li></ul><h3 id="长治电网-ai-调度机器人" tabindex="-1">长治电网 AI 调度机器人 <a class="header-anchor" href="#长治电网-ai-调度机器人" aria-label="Permalink to &quot;长治电网 AI 调度机器人&quot;">​</a></h3><ul><li>国网系统部署，搭载&quot;1+3+5&quot;智能体系</li><li>核心业务耗时缩短 80% 以上</li><li>电网风险扫描覆盖率 100%，周期从 30 分钟 → 分钟级</li><li>重要用户供电路径分析从十几分钟 → 秒级</li><li>五大场景：电网运行感知、设备运维、供电形势评估、风险预控、重要用户保障</li></ul><h3 id="深圳供电局配电网监视-agent" tabindex="-1">深圳供电局配电网监视 Agent <a class="header-anchor" href="#深圳供电局配电网监视-agent" aria-label="Permalink to &quot;深圳供电局配电网监视 Agent&quot;">​</a></h3><ul><li>CPU+GPU 异构 + 大模型融合</li><li>首创&quot;大模型调度、小模型执行分析&quot;联动模式</li><li>应用于配电网监视 &amp; 操作票审核</li><li>百秒零差错完成 N-1 安全校核</li></ul><h3 id="南方电网-大瓦特-大模型" tabindex="-1">南方电网&quot;大瓦特&quot;大模型 <a class="header-anchor" href="#南方电网-大瓦特-大模型" aria-label="Permalink to &quot;南方电网&quot;大瓦特&quot;大模型&quot;">​</a></h3><ul><li>能源行业首个全栈国产化企业级 AI 原生智能执行助手</li><li>落地 700+ 实景场景（调度优化、设备巡检、智能客服等）</li><li>替代超 80% 人工巡检工作</li><li>常规任务处理耗时平均降低 80%</li><li>开箱预置 50+ MCP 和 Skills</li></ul><h2 id="ai-幻觉问题" tabindex="-1">AI 幻觉问题 <a class="header-anchor" href="#ai-幻觉问题" aria-label="Permalink to &quot;AI 幻觉问题&quot;">​</a></h2><p>多家已实质解决：</p><table tabindex="0"><thead><tr><th>方案</th><th>技术手段</th><th>效果</th></tr></thead><tbody><tr><td>&quot;明月&quot;</td><td>知识图谱+强化学习+大模型微调</td><td>规避&quot;幻觉&quot;</td></tr><tr><td>&quot;阿度&quot;</td><td>GRPO 强化学习算法</td><td>精准推理，可解释性</td></tr><tr><td>为恒 WHES OS</td><td>AI 策略解释与归因回放</td><td>首创&quot;黑盒&quot;解释功能</td></tr><tr><td>行业趋势</td><td>大小模型融合</td><td>实测验证替代理论推测</td></tr></tbody></table><h2 id="商业化进展" tabindex="-1">商业化进展 <a class="header-anchor" href="#商业化进展" aria-label="Permalink to &quot;商业化进展&quot;">​</a></h2><h3 id="为恒智能-whes-os" tabindex="-1">为恒智能 WHES OS <a class="header-anchor" href="#为恒智能-whes-os" aria-label="Permalink to &quot;为恒智能 WHES OS&quot;">​</a></h3><ul><li>行业首款 AI-native 原生智能化能源操作系统</li><li>AI Agent 通过自然语言理解用户需求，自动生成能源策略</li><li>实测：项目年均收益提升 8%-15%，调度成本下降 20%</li><li>15 分钟级实时滚动优化</li><li>覆盖工厂峰谷套利、光储充、微电网、VPP 等场景</li><li>2026 年 2 月向港交所递交上市材料</li></ul><h3 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>评价</th></tr></thead><tbody><tr><td>技术成熟度</td><td>已从演示品走向省级 7x24 生产部署</td></tr><tr><td>误报率</td><td>核心难题已解决（知识图谱+强化学习），未公布精确误报率数据</td></tr><tr><td>主要形态</td><td>电网调度侧（与调度员协作），非替代调度员</td></tr><tr><td>市场化交易侧</td><td>仍处早期，AI Agent 参与现货市场交易决策的案例较少</td></tr><tr><td>储能运营侧</td><td>为恒智能等企业已推出 AI Agent 商业化产品</td></tr></tbody></table><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>精确误报率数据未公开披露，难以横向对比</li><li>当前以辅助调度员为主，全自主决策仍有距离</li><li>市场化交易侧 AI Agent 成熟度不足</li><li>行业标准缺失，各家方案差异大，互操作性有限</li><li>对电网安全的高要求意味着 AI Agent 的部署审核周期长</li></ol><hr><p><em>来源：中国电力报、央广网、科技日报、新华网、中国金融信息网</em><em>更新：2026-06-16</em></p>',26)])])}const c=a(o,[["render",d]]);export{A as __pageData,c as default};
